import{_ as e,o as l,c as o,ag as r}from"./chunks/framework.wqPkq5Rj.js";const u=JSON.parse('{"title":"上手配置 · 从熵减官开始","description":"","frontmatter":{},"headers":[],"relativePath":"advanced/entropy-officer.md","filePath":"advanced/entropy-officer.md","lastUpdated":1777169627000}'),t={name:"advanced/entropy-officer.md"};function i(n,a,p,s,c,h){return l(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="上手配置-·-从熵减官开始" tabindex="-1">上手配置 · 从熵减官开始 <a class="header-anchor" href="#上手配置-·-从熵减官开始" aria-label="Permalink to &quot;上手配置 · 从熵减官开始&quot;">​</a></h1><p><img src="https://static.moxtcontent.com/public/resource/ai/gen/7ed648f1-e880-4d45-b4a2-9ab18a4bd894.png" alt="熵减官"></p><h2 id="先说一件关于组织的事" tabindex="-1">先说一件关于组织的事 <a class="header-anchor" href="#先说一件关于组织的事" aria-label="Permalink to &quot;先说一件关于组织的事&quot;">​</a></h2><p>所有组织都有一个共同的宿命：<strong>熵增</strong>。</p><p>文件越来越多，真正有用的越来越少。会议纪要里说的事，没人知道哪些还算数。Notion 里有 300 篇文档，但问 AI 任何问题，它的回答都模棱两可——因为它也不知道哪些是真实的、哪些是过时的。</p><p>「做多」是本能——开新文档容易，删旧文档难；写新决策容易，同步旧文档难。时间一长，每个人都在一堆信息废墟里工作，找不到真相，只能靠口耳相传。</p><p>这不是某家公司的特殊问题。这是信息系统的物理定律。</p><p>Moxt 的第一个答案是：<strong>熵减官</strong>。</p><hr><h2 id="熵减官是什么" tabindex="-1">熵减官是什么 <a class="header-anchor" href="#熵减官是什么" aria-label="Permalink to &quot;熵减官是什么&quot;">​</a></h2><p>它是你的第一个 AI 同事，专门负责一件事：让 Workspace 里的信息始终保持精简和真实。</p><ul><li>过时的文档，它来标记和归档——避免过时信息污染 AI 同事的上下文</li><li>文档之间的矛盾，它来发现和提醒</li><li>某个词或概念全局换了叫法，它来完成全局更新——不只是替换词，是读懂业务之后的一次校准</li><li>每周产出一份「信息健康报告」，告诉团队哪里开始乱了</li></ul><p>它不删内容，只整理。它的工作是让 AI 永远看到最新的、真实的信息状态。</p><hr><h2 id="_10-分钟上手-配置你的第一个" tabindex="-1">10 分钟上手：配置你的第一个 <a class="header-anchor" href="#_10-分钟上手-配置你的第一个" aria-label="Permalink to &quot;10 分钟上手：配置你的第一个&quot;">​</a></h2><h3 id="第一步-创建" tabindex="-1">第一步：创建 <a class="header-anchor" href="#第一步-创建" aria-label="Permalink to &quot;第一步：创建&quot;">​</a></h3><ol><li>在左侧边栏，点击「AI 同事」→「新建」</li><li>给它起个名字（建议就叫「熵减官」，清晰）</li><li>选择头像（随意）</li></ol><h3 id="第二步-确认它的能力范围" tabindex="-1">第二步：确认它的能力范围 <a class="header-anchor" href="#第二步-确认它的能力范围" aria-label="Permalink to &quot;第二步：确认它的能力范围&quot;">​</a></h3><p>创建完成后，先确认它能用什么、能看什么、能调什么：</p><ul><li><strong>Skill</strong>——它有哪些可用的 Skill？熵减官主要用到文件读写，暂时不需要额外 Skill。后续如果你总结了一套归档规范，可以写成 Skill 让它遵循</li><li><strong>文件范围</strong>——它能读取哪些文件？默认可以访问团队空间的所有文件。如果你只想让它管理特定目录，在对话里告诉它</li><li><strong>外部集成</strong>——它能调用哪些外部服务？比如接入 Slack 让它自动通知结果，或接入 GitHub 让它直接读取代码仓库获取最准确的第一手资料</li></ul><h3 id="第三步-告诉它该做什么" tabindex="-1">第三步：告诉它该做什么 <a class="header-anchor" href="#第三步-告诉它该做什么" aria-label="Permalink to &quot;第三步：告诉它该做什么&quot;">​</a></h3><p>直接在对话框里发一段话，告诉它的定位和任务（根据你们的情况修改）：</p><blockquote><p>你是这个团队 Workspace 的信息管理员，负责让 Workspace 里的内容始终保持精简和准确。</p><p>你的核心任务：</p><ol><li>每周扫描一次 Workspace，找出超过 3 个月未更新且疑似过时的文档，列出清单，附上判断理由，发到团队空间的「待处理」文件夹，等人类确认</li><li>发现文档之间有明显矛盾时，创建一个「待核对」标注，通知相关负责人</li><li>当团队决定某个词语、概念统一换用新叫法时，协助完成全局更新</li></ol><p>你不删除任何内容，只归档（移动到 _archived/ 文件夹）。删除需要人类确认。</p></blockquote><h3 id="第四步-让它完成第一次熵减" tabindex="-1">第四步：让它完成第一次熵减 <a class="header-anchor" href="#第四步-让它完成第一次熵减" aria-label="Permalink to &quot;第四步：让它完成第一次熵减&quot;">​</a></h3><p>不要等配好定时任务再开始。现在就让它干一件具体的事：</p><blockquote><p>「扫描一下现在 Workspace 里的所有文档，找出你认为最可能已经过时的 5 个，告诉我为什么。」</p></blockquote><p>看看它找到什么。如果结果靠谱，你就知道它能胜任了。</p><h3 id="第五步-配置定时任务-驱动自主工作" tabindex="-1">第五步：配置定时任务，驱动自主工作 <a class="header-anchor" href="#第五步-配置定时任务-驱动自主工作" aria-label="Permalink to &quot;第五步：配置定时任务，驱动自主工作&quot;">​</a></h3><p>验证完成后，给它设一个定时任务，让它自己跑起来：</p><ul><li>在对话框上方点击定时任务图标</li><li>频率：每周一 早上 9:00</li><li>任务内容：执行一次完整的 Workspace 信息健康检查</li></ul><p>从此它每周一自己运行。你不需要记得这件事，它不会忘。</p><hr><h2 id="它上岗之后" tabindex="-1">它上岗之后 <a class="header-anchor" href="#它上岗之后" aria-label="Permalink to &quot;它上岗之后&quot;">​</a></h2><p>熵减官第一次真正清理完一批文档的那一刻，有些团队成员会有一种奇怪的感觉——</p><p>「原来那些东西一直在那里，我们一直在这堆废墟里工作，但没人注意到。」</p><p>这个感觉值得记住。以后每次有人想「再开一个文档」、「再加一条规定」，可以先问一句：真的有必要吗？</p><p><strong>做少是能力，做多是本能。</strong></p>',37)])])}const b=e(t,[["render",i]]);export{u as __pageData,b as default};
